function normalizeBinaryPath(binaryPath: string): string {
  if (binaryPath === "~") {
    return OS.homedir();
  }
  if (binaryPath.startsWith("~/") || binaryPath.startsWith("~\\")) {
    return Path.join(OS.homedir(), binaryPath.slice(2));
